script.text:
      /* <flatten type="Javascript"> */
function active$NotifyListFilter$(sender) {sender.add_onResponseComplete(on$NotifyListFilter$ResponseComplete);}
function close$NotifyListFilter$(sender) {try {sender.remove_onResponseComplete(on$NotifyListFilter$ResponseComplete);} catch (ex) {}}
function on$NotifyListFilter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array();
      g._notifyType = f.getItemValue('ma_loai_tb');
      g._notifyName = $func.trim(f.getItem('ten_loai_tb%l').value);

      Array.add(k, {Name: 'ma_loai_tb', Opr: '=', Value: g._notifyType, Type: 'String', Ignore: false});
      g._alterTitle = [null, [['%s1', g._notifyType.toString(), true], ['%s2', g._notifyName, true]]];
      g.set_externalKey(k);
      break;
    default:
      break;
  }
}
function set$NotifyListFilter$(f, k) {
  var g = f.grid;
  g._$days = k[0];
  g._$account = k[1];
  g._$customer = k[2];
}
/* </flatten> */
